<section><h1>MI CUENTA</h1><p>Usuario: <b><?=htmlspecialchars(\App\Helpers\Auth::user()['nombre'])?></b> · Plan: <b><?=htmlspecialchars(\App\Helpers\Auth::user()['tipo_usuario'])?></b></p><div class="account-grid"><form class="panel" method="post" action="<?=$config['base_url']?>/cambiar-password"><h3>Cambiar contraseña</h3><?=Csrf::field()?><input type="password" name="password" minlength="8" required><button>Cambiar</button></form><form class="panel" method="post" action="<?=$config['base_url']?>/listas/crear"><h3>Nueva lista</h3><?=Csrf::field()?><input name="nombre" placeholder="Nombre" required><textarea name="descripcion" placeholder="Descripción"></textarea><button>Crear</button></form></div></section><section><h2>PLANES PREMIUM</h2><div class="cards"><?php foreach($plans as $p):?><article class="card plan"><div><h3><?=$p['nombre']?></h3><strong>B/. <?=number_format($p['precio'],2)?></strong><form method="post" action="<?=$config['base_url']?>/premium/<?=$p['id']?>/comprar"><?=Csrf::field()?><select name="metodo_pago"><option>Tarjeta</option><option>Yappy</option><option>Transferencia</option></select><button>Comprar</button></form></div></article><?php endforeach;?></div></section><section><h2>COMPRAR ENTRADAS</h2><div class="cards"><?php foreach($events as $e):?><article class="card"><div><h3><?=$e['nombre']?></h3><p><?=$e['fecha']?> · B/. <?=number_format($e['precio'],2)?></p><form method="post" action="<?=$config['base_url']?>/eventos/<?=$e['id']?>/comprar"><?=Csrf::field()?><input type="number" name="cantidad" min="1" value="1"><button>Comprar</button></form></div></article><?php endforeach;?></div></section><section><h2>FAVORITOS</h2><div class="cards"><?php foreach($favorites as $f):?><article class="card"><div><h3><?=$f['nombre']?></h3><p><?=$f['artista']?></p></div></article><?php endforeach;?></div></section><section><h2>MIS LISTAS</h2><?php foreach($lists as $l):?><form class="panel" method="post" action="<?=$config['base_url']?>/listas/agregar"><b><?=htmlspecialchars($l['nombre'])?></b><?=Csrf::field()?><input type="hidden" name="lista_id" value="<?=$l['id']?>"><select name="cancion_id"><?php foreach($songs as $s):?><option value="<?=$s['id']?>"><?=$s['nombre']?></option><?php endforeach;?></select><button>Agregar canción</button></form><?php endforeach;?></section><section><h2>HISTORIAL DE COMPRAS</h2><div class="table-wrap"><table><tr><th>Tipo</th><th>Subtotal</th><th>ITBMS</th><th>Total</th><th>Fecha</th></tr><?php foreach($purchases as $x):?><tr><td><?=$x['tipo']?></td><td>B/. <?=$x['subtotal']?></td><td>B/. <?=$x['itbms']?></td><td>B/. <?=$x['total']?></td><td><?=$x['fecha']?></td></tr><?php endforeach;?></table></div></section>